html:
{#- Extra context is injected by frappe_giving.api.receipts.download_yearly_statement -#}
{%- set company = frappe.get_doc("Company", doc.statement_company) if doc.statement_company else None -%}
{%- set address_name = frappe.db.get_value("Dynamic Link", {"link_doctype": "Company", "link_name": doc.statement_company, "parenttype": "Address"}, "parent") if doc.statement_company else None -%}
{%- set address = frappe.db.get_value("Address", address_name, ["address_line1", "address_line2", "city", "state", "pincode", "country"], as_dict=True) if address_name else None -%}
<div class="yearly-statement">
  <style>
    .yearly-statement { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; color: #1f2937; max-width: 760px; margin: 0 auto; }
    .yearly-statement .org { text-align: center; margin-bottom: 20px; padding-bottom: 12px; border-bottom: 2px solid #1f2937; }
    .yearly-statement .org .name { font-size: 22px; font-weight: 700; }
    .yearly-statement .org .addr { font-size: 12px; color: #6b7280; margin-top: 6px; line-height: 1.5; }
    .yearly-statement h1 { text-align: center; font-size: 16px; letter-spacing: 0.15em; text-transform: uppercase; color: #374151; margin: 20px 0 6px; }
    .yearly-statement h1 .year { color: #1f2937; }
    .yearly-statement .parties { display: flex; gap: 32px; margin: 20px 0 16px; font-size: 13px; }
    .yearly-statement .parties .col { flex: 1; }
    .yearly-statement .parties .label { color: #6b7280; text-transform: uppercase; font-size: 11px; letter-spacing: 0.4px; }
    .yearly-statement table.lines { width: 100%; border-collapse: collapse; font-size: 12px; margin-top: 8px; }
    .yearly-statement table.lines th { text-align: left; padding: 8px; background: #f3f4f6; border-bottom: 1px solid #d1d5db; text-transform: uppercase; font-size: 11px; letter-spacing: 0.4px; color: #4b5563; }
    .yearly-statement table.lines td { padding: 8px; border-bottom: 1px solid #e5e7eb; vertical-align: top; }
    .yearly-statement table.lines td.num, .yearly-statement table.lines th.num { text-align: right; white-space: nowrap; }
    .yearly-statement .totals { margin-top: 14px; margin-left: auto; width: 300px; font-size: 13px; }
    .yearly-statement .totals tr td { padding: 4px 8px; }
    .yearly-statement .totals tr.grand td { font-weight: 700; font-size: 15px; border-top: 2px solid #1f2937; padding-top: 8px; }
    .yearly-statement .notice { font-size: 11px; color: #4b5563; margin-top: 32px; padding-top: 12px; border-top: 1px solid #e5e7eb; line-height: 1.6; }
  </style>

  {% if company %}
  <div class="org">
    <div class="name">{{ company.company_name }}</div>
    {% if address %}
    <div class="addr">
      {{ address.address_line1 or "" }}{% if address.address_line2 %}, {{ address.address_line2 }}{% endif %}
      {% if address.city %}<br>{{ address.city }}{% if address.state %}, {{ address.state }}{% endif %}{% if address.pincode %} {{ address.pincode }}{% endif %}{% endif %}
      {% if address.country %}<br>{{ address.country }}{% endif %}
    </div>
    {% endif %}
  </div>
  {% endif %}

  <h1>{{ _("Consolidated Donation Statement") }} · <span class="year">{{ doc.statement_year }}</span></h1>
  <div style="text-align: center; font-size: 12px; color: #6b7280;">{{ _("Issued {0}").format(frappe.utils.formatdate(frappe.utils.nowdate())) }}</div>

  <div class="parties">
    <div class="col">
      <div class="label">{{ _("Donor") }}</div>
      <div style="font-weight: 600;">{{ doc.donor_name }}</div>
      <div style="color: #6b7280; font-size: 12px;">{{ doc.email }}</div>
      <div style="color: #6b7280; font-size: 11px;">{{ doc.name }}</div>
    </div>
    <div class="col" style="text-align: right;">
      <div class="label">{{ _("Tax Year") }}</div>
      <div style="font-weight: 600;">{{ doc.statement_year }}</div>
      <div style="color: #6b7280; font-size: 12px;">{{ _("{0} donation(s)").format(doc.statement_line_items|length) }}</div>
    </div>
  </div>

  <table class="lines">
    <thead>
      <tr>
        <th>{{ _("Date") }}</th>
        <th>{{ _("Receipt No.") }}</th>
        <th>{{ _("Campaign") }}</th>
        <th>{{ _("Frequency") }}</th>
        <th class="num">{{ _("Amount") }}</th>
      </tr>
    </thead>
    <tbody>
      {% for item in doc.statement_line_items %}
      <tr>
        <td>{{ frappe.utils.formatdate(item.date) }}</td>
        <td style="font-family: ui-monospace, monospace; font-size: 11px;">{{ item.name }}</td>
        <td>{{ item.campaign_label or item.campaign }}</td>
        <td>{{ item.frequency }}</td>
        <td class="num">{{ frappe.utils.fmt_money(item.amount, currency=item.currency) }}</td>
      </tr>
      {% endfor %}
    </tbody>
  </table>

  <table class="totals">
    {% for row in doc.statement_currency_breakdown %}
    <tr><td>{{ _("Total") }} ({{ row.currency }})</td><td class="num" align="right">{{ frappe.utils.fmt_money(row.total, currency=row.currency) }}</td></tr>
    {% endfor %}
    {% if doc.statement_total_usd %}
    <tr class="grand"><td>{{ _("Total (USD equivalent)") }}</td><td class="num" align="right">{{ frappe.utils.fmt_money(doc.statement_total_usd, currency="USD") }}</td></tr>
    {% endif %}
  </table>

  <div class="notice">
    <p>{{ _("This statement consolidates all confirmed donations received from the named donor during the tax year shown. No goods or services were provided in exchange for these contributions. Donations are tax-deductible to the extent allowed by law.") }}</p>
    {% if company %}<p>{{ _("Thank you for your continued support of {0}.").format(company.company_name) }}</p>{% endif %}
  </div>
</div>
